import React, { useRef } from 'react';
import { useIntroAnimation } from '../useAnimations'; 
import './Intro.css';

// 부모(App.js)로부터 onStart 함수를 받아옵니다.
function Intro({ onStart }) {
  const posterARef = useRef(null);
  const posterBRef = useRef(null);
  const titleImageRef = useRef(null); 
  const buttonRef = useRef(null);

  // 애니메이션 로직 유지
  useIntroAnimation(posterARef, posterBRef, titleImageRef, buttonRef);

  return (
    <div className="intro-container">
      {/* 배경 이미지들: PUBLIC_URL 적용 */}
      <img 
        ref={posterARef} 
        src={process.env.PUBLIC_URL + "/assets/posterA.png"} 
        className="poster-bg poster-a" 
        alt="배경 A" 
      />
      <img 
        ref={posterBRef} 
        src={process.env.PUBLIC_URL + "/assets/posterB.png"} 
        className="poster-bg poster-b" 
        alt="배경 B" 
      />
      
      <div className="content-wrapper">
        {/* 제목 이미지: PUBLIC_URL 적용 */}
        <img 
          ref={titleImageRef} 
          src={process.env.PUBLIC_URL + "/assets/intro_title.png"} 
          alt="당신의 단종은 누구인가요?" 
          className="intro-title-img" 
        />
        
        <button 
          ref={buttonRef} 
          className="start-button" 
          onClick={onStart} 
        >
          Next
        </button>
      </div>
    </div>
  );
}

export default Intro;